Rules.InvariantScript:
Patch(
    Equipment,
    ThisItem,
    {
        CheckedBy: Self.Text,
        LastCheckedAt: Now()
    }
);

Set(checkedByConfirmedID, ThisItem.ID);

Set(showEquipmentErrors, false);
Set(equipmentErrorID, Blank());

Set(editingCheckedByID, Blank());

Notify("Checked by updated.", NotificationType.Success)

Patch(
    Equipment,
    ThisItem,
    {
        Notes: Self.Text,
        LastCheckedAt: Now()
    }
);

Set(editingEquipmentID, Blank());

Notify("Notes updated.", NotificationType.Success)

Patch(
    Equipment,
    ThisItem,
    {
        Notes: Self.Text,
        LastCheckedAt: Now()
    }
);

Set(editingEquipmentID, Blank());

Notify("Notes updated.", NotificationType.Success)

If(
    checkedByConfirmedID <> ThisItem.ID,

    Set(showEquipmentErrors, true);
    Set(equipmentErrorID, ThisItem.ID);
    Notify("Please confirm who checked this equipment before updating status.", NotificationType.Error),

    Patch(
        Equipment,
        ThisItem,
        {
            CurrentStatus: {Value: "Ok"},
            LastCheckedAt: Now()
        }
    );

    Set(showEquipmentErrors, false);
    Set(equipmentErrorID, Blank());
    Notify("Equipment marked as OK.", NotificationType.Success)
)

If(
    checkedByConfirmedID <> ThisItem.ID,

    Set(showEquipmentErrors, true);
    Set(equipmentErrorID, ThisItem.ID);
    Notify("Please confirm who checked this equipment before updating status.", NotificationType.Error),

    Patch(
        Equipment,
        ThisItem,
        {
            CurrentStatus: {Value: "Repair"},
            LastCheckedAt: Now()
        }
    );

    Set(showEquipmentErrors, false);
    Set(equipmentErrorID, Blank());
    Notify("Equipment marked for repair.", NotificationType.Warning)
)

If(
    checkedByConfirmedID <> ThisItem.ID,

    Set(showEquipmentErrors, true);
    Set(equipmentErrorID, ThisItem.ID);
    Notify("Please confirm who checked this equipment before updating status.", NotificationType.Error),

    Patch(
        Equipment,
        ThisItem,
        {
            CurrentStatus: {Value: "Missing"},
            LastCheckedAt: Now()
        }
    );

    Set(showEquipmentErrors, false);
    Set(equipmentErrorID, Blank());
    Notify("Equipment marked as missing.", NotificationType.Error)
)
